  1	import * as React from 'react';
  2	import { useODFSystemFlagsSelector } from '@odf/core/redux';
  3	import { useGetClusterDetails } from '@odf/core/redux/utils';
  4	import { secretResource } from '@odf/core/resources';
  5	import { getResourceInNs } from '@odf/core/utils';
  6	import { decodeRGWPrefix, getDataResiliencyState } from '@odf/ocs/utils';
  7	import { CephObjectStoreModel, NooBaaSystemModel } from '@odf/shared';
  8	import {
  9	  useCustomPrometheusPoll,
 10	  usePrometheusBasePath,
 11	} from '@odf/shared/hooks/custom-prometheus-poll';
 12	import useAlerts from '@odf/shared/monitoring/useAlert';
 13	import { K8sResourceKind } from '@odf/shared/types';
 14	import { useCustomTranslation } from '@odf/shared/useCustomTranslationHook';
 15	import {
 16	  alertURL,
 17	  filterNooBaaAlerts,
 18	  filterRGWAlerts,
 19	} from '@odf/shared/utils';
 20	import { referenceForModel } from '@odf/shared/utils';
 21	import { useK8sWatchResource } from '@openshift-console/dynamic-plugin-sdk';
 22	import { SubsystemHealth } from '@openshift-console/dynamic-plugin-sdk/lib/extensions/dashboard-types';
 23	import {
 24	  AlertsBody,
 25	  AlertItem,
 26	} from '@openshift-console/dynamic-plugin-sdk-internal';
 27	import * as _ from 'lodash-es';
 28	import {
 29	  Gallery,
 30	  GalleryItem,
 31	  Card,
 32	  CardHeader,
 33	  CardBody,
 34	  CardTitle,
 35	} from '@patternfly/react-core';
 36	import { StatusType } from '../../../constants';
 37	import {
 38	  StatusCardQueries,
 39	  dataResiliencyQueryMap,
 40	  ObjectServiceDashboardQuery,
 41	} from '../../../queries';
 42	import { ObjectServiceStatus } from './object-service-health';
 43	import { getNooBaaState, getRGWHealthState } from './statuses';
 44	import '../../../style.scss';
 45	
 46	const noobaaResource = {
 47	  kind: referenceForModel(NooBaaSystemModel),
 48	  isList: true,
 49	};
 50	
 51	const cephObjectStoreResource = {
 52	  kind: referenceForModel(CephObjectStoreModel),
 53	  isList: true,
 54	};
 55	
 56	const ObjectStorageAlerts = () => {
 57	  const [alerts, loaded, loadError] = useAlerts();
 58	  // ToDo (epic 4422): Get StorageCluster name and namespace from the Alert object
 59	  // and filter Alerts based on that for a particular cluster.
 60	  const filteredAlerts =
 61	    loaded && !loadError && !_.isEmpty(alerts)
 62	      ? [...filterNooBaaAlerts(alerts), ...filterRGWAlerts(alerts)]
 63	      : [];
 64	
 65	  return (
 66	    <AlertsBody error={!_.isEmpty(loadError)}>
 67	      {loaded &&
 68	        filteredAlerts.length > 0 &&
 69	        filteredAlerts.map((alert) => (
 70	          <AlertItem
 71	            key={alertURL(alert, alert?.rule?.id)}
 72	            alert={alert as any}
 73	          />
 74	        ))}
 75	    </AlertsBody>
 76	  );
 77	};
 78	
 79	const StatusCard: React.FC<{}> = () => {
 80	  const { clusterNamespace: clusterNs } = useGetClusterDetails();
 81	  const { systemFlags } = useODFSystemFlagsSelector();
 82	  const isRGWSupported = systemFlags[clusterNs]?.isRGWAvailable;
 83	  const isMCGSupported = systemFlags[clusterNs]?.isNoobaaAvailable;
 84	  const managedByOCS = systemFlags[clusterNs]?.ocsClusterName;
 85	
 86	  const { t } = useCustomTranslation();
 87	
 88	  const [secretData, secretLoaded, secretLoadError] =
 89	    useK8sWatchResource<K8sResourceKind>(secretResource(clusterNs));
 90	  const [noobaas, noobaaLoaded, noobaaLoadError] =
 91	    useK8sWatchResource<K8sResourceKind[]>(noobaaResource);
 92	  const [rgws, rgwLoaded, rgwLoadError] = useK8sWatchResource<
 93	    K8sResourceKind[]
 94	  >(cephObjectStoreResource);
 95	
 96	  const noobaa = getResourceInNs(noobaas, clusterNs);
 97	  const rgw = getResourceInNs(rgws, clusterNs);
 98	
 99	  const rgwPrefix = React.useMemo(
100	    () =>
101	      isRGWSupported && secretLoaded && !secretLoadError
102	        ? decodeRGWPrefix(secretData)
103	        : '',
104	    [secretData, secretLoaded, secretLoadError, isRGWSupported]
105	  );
106	
107	  const rgwResiliencyQuery = dataResiliencyQueryMap[
108	    ObjectServiceDashboardQuery.RGW_REBUILD_PROGRESS_QUERY
109	  ](rgwPrefix, managedByOCS);
110	
111	  const [healthStatusResult, healthStatusError] = useCustomPrometheusPoll({
112	    query: StatusCardQueries.HEALTH_QUERY,
113	    endpoint: 'api/v1/query' as any,
114	    basePath: usePrometheusBasePath(),
115	  });
116	  const [progressResult, progressError] = useCustomPrometheusPoll({
117	    query: StatusCardQueries.MCG_REBUILD_PROGRESS_QUERY,
118	    endpoint: 'api/v1/query' as any,
119	    basePath: usePrometheusBasePath(),
120	  });
121	  const [rgwResiliencyResult, rgwResiliencyError] = useCustomPrometheusPoll({
122	    query: rgwResiliencyQuery,
123	    endpoint: 'api/v1/query' as any,
124	    basePath: usePrometheusBasePath(),
125	  });
126	
127	  const MCGState = getNooBaaState(
128	    [{ response: healthStatusResult, error: healthStatusError }],
129	    t,
130	    {
131	      loaded: noobaaLoaded,
132	      loadError: noobaaLoadError,
133	      data: noobaa,
134	    }
135	  );
136	
137	  const RGWState =
138	    !rgwLoadError && rgwLoaded ? getRGWHealthState(rgw) : undefined;
139	
140	  const dataResiliencyState: SubsystemHealth = getDataResiliencyState(
141	    [{ response: progressResult, error: progressError }],
142	    t
143	  );
144	
145	  const RGWResiliencyState = getDataResiliencyState(
146	    [{ response: rgwResiliencyResult, error: rgwResiliencyError }],
147	    t
148	  );
149	
150	  return (
151	    <Card className="odf-overview-card--gradient">
152	      <CardHeader>
153	        <CardTitle>{t('Status')}</CardTitle>
154	      </CardHeader>
155	      <CardBody>
156	        <Gallery className="odf-overview-status__health" hasGutter>
157	          <GalleryItem>
158	            <ObjectServiceStatus
159	              RGWMetrics={isRGWSupported ? RGWState : undefined}
160	              MCGMetrics={isMCGSupported ? MCGState : undefined}
161	              statusType={StatusType.HEALTH}
162	            />
163	          </GalleryItem>
164	          <GalleryItem>
165	            <ObjectServiceStatus
166	              RGWMetrics={isRGWSupported ? RGWResiliencyState : undefined}
167	              MCGMetrics={isMCGSupported ? dataResiliencyState : undefined}
168	              statusType={StatusType.RESILIENCY}
169	            />
170	          </GalleryItem>
171	        </Gallery>
172	        <ObjectStorageAlerts />
173	      </CardBody>
174	    </Card>
175	  );
176	};
177	
178	export default StatusCard;

